import math

def fact(n):
    if n==0:
        return 1
    else:
        return n*fact(n-1)

def nCr(n,r):
    f = math.factorial
    return f(n) // f(r) // f(n-r)

def div(n):
    div=[]
    for i in range(1,n+1):
        if n%i==0:
            div.append(i)
    return div

def prod(n):
    prod=1
    for i in range(0,len(n)):
        prod=prod*n[i]
    return prod

